def main():
    guides_data = load("guides.json")
    existing_slugs = {g["slug"] for g in guides_data["guides"]}

    added = []
    skipped = []

    for guide in NEW_GUIDES:
        if guide["slug"] in existing_slugs:
            skipped.append(guide["slug"])
            continue
        guides_data["guides"].append(guide)
        added.append(guide["slug"])

    save("guides.json", guides_data)

    print(f"Total guides now: {len(guides_data['guides'])}")
    print(f"Added {len(added)}: {', '.join(added)}")
    if skipped:
        print(f"Skipped {len(skipped)} (already exist): {', '.join(skipped)}")


if __name__ == "__main__":
    main()
